input.script:
// Main workflow orchestrator
const event = event();
const metadata = {
  pod_name: event['event.kubernetes_pod_name'] || 'unknown',
  namespace: event['event.kubernetes_namespace'] || 'default',
  cluster: event['event.kubernetes_cluster_name'] || 'unknown',
  service: event['event.service_name'] || 'unknown',
  severity: event['event.severity'] || 'MEDIUM',
  failure_reason: event['event.failure_reason'] || 'Pod failure detected',
  event_id: event['event.id'] || '',
  timestamp: new Date().toISOString()
};

return {
  status: 'workflow_started',
  pod_metadata: metadata,
  next_steps: [
    '1. Create PagerDuty Incident',
    '2. Query Dynatrace Pod Details',
    '3. Analyze Failure Type',
    '4. Generate Remediation Plan',
    '5. Create Git Commit',
    '6. Trigger ArgoCD Sync',
    '7. Wait for Sync',
    '8. Verify Remediation',
    '9. Resolve or Escalate',
    '10. Send Notification'
  ],
  message: `Workflow started for pod ${metadata.pod_name} in ${metadata.cluster}. Edit workflow in Dynatrace UI to add remaining tasks.`
};
